SELECT * 
FROM netflow_records 
WHERE anomaly_score = (
    SELECT MAX(anomaly_score) 
    FROM netflow_records
);

SELECT *
FROM netflow_records
WHERE flow_start_ms BETWEEN 1672531200000 AND 1675123199999;

SELECT threat_level 
FROM netflow_records 
ORDER BY threat_level DESC;

SELECT ip_address, last_seen
FROM ip_addresses
WHERE ip_type = 'source' AND last_seen < DATE('now', '-30 day');

SELECT COUNT(DISTINCT country)
FROM netflow_records
WHERE protocol = 'ICMP';

SELECT COUNT(*)
FROM netflow_records
WHERE netflow_version != '9';

SELECT DISTINCT security_risk
FROM protocols
WHERE protocol_name IS NOT NULL;

SELECT device_id, src_ip, dst_ip, protocol, in_bytes
FROM netflow_records
ORDER BY in_bytes DESC;

SELECT record_id
FROM netflow_records
WHERE anomaly_score > (SELECT AVG(anomaly_score) FROM netflow_records);
